use std::collections::BinaryHeap;

fn solve(value: Vec<i64>, limit: Vec<i64>) -> i64 {
    let n = value.len();
    let mut elements: Vec<(i64, i64, usize)> = Vec::with_capacity(n);
    for i in 0..n {
        elements.push((limit[i], -value[i], i));
    }
    elements.sort_by(|a, b| a.0.cmp(&b.0));

    let mut max_heap = BinaryHeap::new();
    let mut res = 0;
    let mut active_count = 0;
    let mut ptr = 0;

    while ptr < n || !max_heap.is_empty() {
        while ptr < n && elements[ptr].0 > active_count {
            let (_, neg_val, i) = elements[ptr];
            max_heap.push((neg_val, i));
            ptr += 1;
        }

        if max_heap.is_empty() {
            break;
        }

        let (neg_val, i) = max_heap.pop().unwrap();
        res += value[i];
        active_count += 1;
    }

    res
}
